<script>
window.addEventListener("ab.BridgeReady", function () {

  if (window.__iamTrackingInstalled) return;
  window.__iamTrackingInstalled = true;

  function sanitize(str){
    return (str || "unknown")
      .trim()
      .replace(/[^A-Za-z0-9 _-]/g,"")
      .slice(0,255);
  }

  document.addEventListener("click", function(e){

    var el = e.target.closest("a,button");
    if(!el) return;

    var href = el.getAttribute("href");
    var rawId = el.getAttribute("data-braze-id") || el.innerText || "unknown";
    var buttonId = sanitize(rawId);
    var buttonText = (el.innerText || "").trim();

    try{

      if(window.brazeBridge){

        if(typeof brazeBridge.logClick === "function"){
          brazeBridge.logClick(buttonId);
        }

        if(typeof brazeBridge.logCustomEvent === "function"){
          brazeBridge.logCustomEvent("iam_click_event",{
            button_id: buttonId,
            button_text: buttonText,
            campaign_name: IAM_CAMPAIGN_NAME,
            page_url: window.location.href,
            timestamp: new Date().toISOString()
          });
        }

        if(typeof brazeBridge.requestImmediateDataFlush === "function"){
          brazeBridge.requestImmediateDataFlush();
        }

      }

    }catch(err){
      console.log(err);
    }

    if(href && href !== "#"){
      var target = (el.getAttribute("target") || "").toLowerCase();
      e.preventDefault();
      setTimeout(function(){
        var parentWin = (window.iam_config && window.iam_config.parentWindow) ? window.iam_config.parentWindow : window;
        if(target === "_blank"){
          parentWin.open(href, "_blank", "noopener,noreferrer");
        } else {
          parentWin.location.href = href;
        }
      },250);
    }

  },true);

});
</script>


