      : window.top.document.querySelector('.ab-iam-root'),
    iframe: isDashboard
      ? document.documentElement
      : window.top.document.querySelector('iframe.ab-in-app-message'),
    parentWindow: isDashboard ? window : window.top,
  };

  function resizeIAM() {
    setTimeout(function () {
      var container = document.querySelector('.braze-slideup-container');
      if (!container || !window.iam_config.iframe) return;

      /* top + bottom overflow buffer */
      var height = container.offsetHeight + 30;
      window.iam_config.iframe.style.height = height + 'px';
    }, 100);
  }

  resizeIAM();
  document.body.addEventListener('click', resizeIAM);
  window.iam_config.parentWindow.addEventListener('resize', resizeIAM);

})();
</script>

