<!-- ================= CLOSE ON OUTSIDE CLICK ================= -->
<script>
(function () {

  function setupOutsideClickClose() {
    var container = document.querySelector('.braze-slideup-container');
    if (!container) return;

    var docToUse = document;

    try {
      if (window.iam_config && window.iam_config.parentWindow) {
        docToUse = window.iam_config.parentWindow.document;
      }
    } catch (e) {
      docToUse = document;
    }

    // ✅ Add common cookie/overlay selectors here
    var IGNORE_CLICK_SELECTORS = [
      /* OneTrust */
      '#onetrust-banner-sdk',
      '#onetrust-consent-sdk',
      '.ot-sdk-container',
      '.otFloatingRoundedCorner',
      '.ot-sdk-row',

      /* Cookiebot */
      '#CybotCookiebotDialog',
      '#CybotCookiebotDialogBody',
      '.CybotCookiebotDialog',

      /* TrustArc */
      '#truste-consent-track',
      '.truste_box_overlay',
      '.truste_overlay',

      /* Generic cookie banners */
      '.cookie-banner',
      '.cookie-consent',
      '.cookie-notice',
      '[data-cookie-banner]',
      '[id*="cookie"]',
      '[class*="cookie"]',

      /* Other overlays/widgets (optional) */
      '#intercom-container',
      '.intercom-lightweight-app',
      '#drift-widget',
      '#chat-widget',
    ];

    function isInsideIgnoredOverlay(target) {
      if (!target || !target.closest) return false;

      for (var i = 0; i < IGNORE_CLICK_SELECTORS.length; i++) {
        try {
          if (target.closest(IGNORE_CLICK_SELECTORS[i])) return true;
        } catch (e) {}
      }
      return false;
    }

    docToUse.addEventListener('click', function (event) {

      // 1) If click is inside cookie banner / overlay → ignore
      if (isInsideIgnoredOverlay(event.target)) return;

      // 2) If click is inside IAM → ignore
      if (container.contains(event.target)) return;

      // 3) Otherwise close
      brazeBridge.logClick('clicked_outside_to_close');
      brazeBridge.closeMessage();

    }, true);
  }

  setTimeout(setupOutsideClickClose, 250);

})();
</script>

